def countNumber(n: int) -> int:
  result = 0
  for i in range(1, 10): # Corresponds to for (int i = 1; i <= 9; i++)
    s = [] # Python list used as a stack (append for push, pop for pop)
    if i <= n:
      s.append(i) # Push i onto the stack
      result += 1
    while s: # Corresponds to while (!s.empty())
      tp = s.pop() # Pop the top element (equivalent to peek then pop in Java's context here)
      # The loop for 'j' starts from the last digit of 'tp'
      # and goes up to 9. This ensures non-decreasing digits.
      for j in range(tp % 10, 10): # Corresponds to for (int j = tp % 10; j <= 9; j++)
        x = tp * 10 + j # Form the new number by appending digit 'j'
        if x <= n:
          s.append(x) # Push x onto the stack
          result += 1
  return result

