def number_of_paths ( m : int , n : int ) -> int :
  count = [ [ 0 for _ in range ( n ) ] for _ in range ( m ) ]
  # Initialize first column of count[][] matrix
  for i in range ( m ) :
    count [ i ] [ 0 ] = 1
  # Initialize first row of count[][] matrix
  for j in range ( n ) :
    count [ 0 ] [ j ] = 1
  # Calculate count of paths for other cells
  for i in range ( 1 , m ) :
    for j in range ( 1 , n ) :
