def MatrixChainOrder(p, i, j):
  if i == j:
    return 0
  min_val = float('inf') # Equivalent to Integer.MAX_VALUE
  for k in range(i, j): # Loop from i to j-1 (exclusive of j)
    count = MatrixChainOrder(p, i, k) + \
            MatrixChainOrder(p, k + 1, j) + \
            p[i - 1] * p[k] * p[j]
    if count < min_val:
      min_val = count
  return min_val

